import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./verifyotp.css"; // Ensure you have the CSS file for styling

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [otpError, setOtpError] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const navigate = useNavigate();

  // Redirect to Forgot Password if OTP request is not found in sessionStorage
  useEffect(() => {
    if (!sessionStorage.getItem("otpRequested")) {
      navigate("/forgot-password");
    }
  }, [navigate]);

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setOtpError("");
    setOtpMessage("");

    if (!otp.trim()) {
      setOtpError("OTP is required.");
      return;
    }

    if (!/^\d{6}$/.test(otp)) {
      setOtpError("Invalid OTP format. Must be 6 digits.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", { otp });

      if (response.data.success) {
        setOtpMessage("OTP Verified Successfully!");
        sessionStorage.removeItem("otpRequested"); // Remove OTP request flag
        setTimeout(() => navigate("/reset-password"), 2000); // Redirect to Reset Password page
      } else {
        setOtpError(response.data.message);
      }
    } catch (err) {
      setOtpError("Error verifying OTP. Please try again.");
      console.error("OTP Verification Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return React.createElement(
    "div",
    { className: "verify-otp-container" },
    React.createElement("img", { src: "/logo.png", alt: "Logo", className: "logo" }),
    React.createElement(
      "div",
      { className: "verify-otp-card" },
      React.createElement("h2", null, "Verify OTP"),
      React.createElement("p", null, "Enter the 6-digit OTP sent to your email"),
      React.createElement(
        "form",
        { onSubmit: handleOtpSubmit },
        React.createElement(
          "div",
          { className: "input-group" },
          React.createElement("span", { className: "icon" }, "🔒"),
          React.createElement("input", {
            type: "text",
            placeholder: "Enter OTP",
            value: otp,
            onChange: (e) => setOtp(e.target.value),
            maxLength: "6",
            required: true,
            disabled: isSubmitting
          })
        ),
        React.createElement(
          "button",
          { type: "submit", className: "verify-otp-button", disabled: isSubmitting },
          isSubmitting ? "Verifying..." : "Verify OTP"
        )
      ),
      React.createElement(
        "div",
        { className: "message-container" },
        otpMessage ? React.createElement("p", { className: "success-message" }, otpMessage) : null,
        otpError ? React.createElement("p", { className: "error-message" }, otpError) : null
      ),
      React.createElement("a", { href: "/forgot-password", className: "back-link" }, "Resend OTP")
    )
  );
};

export default VerifyOtpPage;
